<template>
   <PopupsList
      @showPopup="showPopup = $event"

      :settings="settings"
      :levelList="levelList"
      :ratingList="ratingList"
      :lastResault="lastResault"

      :timerStatus="timer.status"
      :stopTimer="timer.stop"
      :startTimer="timer.start"
      :convertTime="convertTime"

      :showMainMenu="showMainMenu"
      :startPlay="startPlay"
      :hidePlayField="hidePlayField"

      :toggleMusic="toggleMusic">
   </PopupsList>
   <MainMenu
      @showMainMenu="showMainMenu = $event"

      :showPopup="showPopup"
      :startPlay="startPlay">
   </MainMenu>
   <TopPanel
      @timer="timer = $event"
      :convertTime="convertTime"

      :showPopup="showPopup">
   </TopPanel>
   <PlayField
      @startPlay="startPlay = $event"
      @hidePlayField="hidePlayField = $event"

      :settings="settings"
      :showPopup="showPopup"

      :stopTimer="timer.stop"
      :startTimer="timer.start">
   </PlayField>
   <MainBackground></MainBackground>
   <audio ref="soundtrack"
      :src="require('@/assets/sounds/soundtrack.mp3')" loop hidden>
      <track default kind="captions" />
   </audio>
</template>

<script>
import MainMenu from '@/components/MainMenu.vue';
import MainBackground from '@/components/MainBackground.vue';
import PlayField from '@/components/PlayField.vue';
import TopPanel from '@/components/TopPanel.vue';
import PopupsList from '@/components/PopupsList.vue';

export default {
   name: 'App',
   data() {
      return {
         settings: {
            music: false,
            level: {
               name: 'easy',
               rowsCount: 3,
               maxTime: 60000,
               uniqueCubesCount: 4,
               hasEmptyCell: true,
            },
         },
         levelList: [
            { name: 'easy', rowsCount: 3, maxTime: 60000 },
            { name: 'medium', rowsCount: 4, maxTime: 90000 },
            { name: 'hard', rowsCount: 5, maxTime: 90000 },
            { name: 'very hard', rowsCount: 6, maxTime: 90000 },
         ],
         ratingList: {
            easy: [],
            medium: [],
            hard: [],
            'very hard': [],
         },
         lastResault: {
            score: null,
            starsCount: null,
         },
         timer: {},
         isActive: {
            mainMenu: false,
            playField: false,
            background: false,
            topPanel: false,
         },
      };
   },
   components: {
      PopupsList,
      MainMenu,
      TopPanel,
      PlayField,
      MainBackground,
   },
   methods: {
      showMainMenu() {},
      showPopup() {},
      startPlay() {},
      hidePlayField() {},
      convertTime(time) {
         const date = new Date(time);
         const min = (`${date.getMinutes()}`).padStart(2, '0');
         const sec = (`${date.getSeconds()}`).padStart(2, '0');
         const convertedTime = `${min}:${sec}`;
         return convertedTime;
      },
      enableMusic() {
         const hasMusicEnabled = this.settings.music;
         if (hasMusicEnabled) {
            this.$refs.soundtrack.play();
         } else {
            this.$refs.soundtrack.pause();
         }
      },
      toggleMusic() {
         this.settings.music = !this.settings.music;
         localStorage.setItem('settings', JSON.stringify(this.settings));

         this.enableMusic();
      },
   },
   beforeMount() {
      const hasSettingsFromLocalStorage = (localStorage.getItem('settings') !== null);
      if (hasSettingsFromLocalStorage) {
         this.settings = JSON.parse(localStorage.getItem('settings'));
      } else {
         localStorage.setItem('settings', JSON.stringify(this.settings));
      }

      const hasRatingFromLocalStorage = (localStorage.getItem('rating') !== null);
      if (hasRatingFromLocalStorage) {
         this.ratingList = JSON.parse(localStorage.getItem('rating'));
      } else {
         localStorage.setItem('rating', JSON.stringify(this.ratingList));
      }
   },
   mounted() {
      this.enableMusic();
   },
};
</script>

