<template>
   <div class="main-menu" :class="{ active: this.$parent.isActive.mainMenu }">
      <div class="main-menu-top">
         <button @click="showPopup('rating')" class="rating-btn" data-popup-name="rating">
            <img src="@/assets/images/main-menu/btns/rating.png" alt="rating button">
         </button>
         <button @click="showPopup('settings')" class="settings-btn">
            <img src="@/assets/images/main-menu/btns/settings.png" alt="settings button">
         </button>
      </div>
      <img class="main-menu-logo" src="@/assets/images/main-menu/logo.png" alt="game logo">
      <button @click="clickPlay()" class="play-btn">
         <img src="@/assets/images/main-menu/btns/play.png" alt="play button">
      </button>
   </div>
</template>

<script>
export default {
   props: ['showPopup', 'startPlay'],
   methods: {
      showMainMenu(delay = 1000) {
         setTimeout(() => {
            this.$parent.isActive.mainMenu = true;
            this.$parent.isActive.background = true;
         }, delay);
      },
      hideMainMenu() {
         this.$parent.isActive.mainMenu = false;
         this.$parent.isActive.background = false;
      },
      clickPlay() {
         this.hideMainMenu();
         this.startPlay();
      },
   },
   mounted() {
      this.showMainMenu(2000);
      this.$emit('showMainMenu', this.showMainMenu);
   },
};
</script>

