<template>
   <div class="popup" :class="{ active: popup.isActive }">
      <div :class="{ ['popup__'+popup.name]: popup.name, active: popup.isActive }">
         <button v-if="!isVictory() && !isDefeat()"
            class="popup-hide"
            @click="hidePopup()">
            <img src="@/assets/images/popups/btns/close.png" alt="close button">
         </button>
         <div class="popup-header">
            <h2>{{ popup.name }}</h2>
            <img src="@/assets/images/popups/header.png" alt="">
         </div>
         <div v-if="isPause()" class="popup-content">
            <h2>take a cup of tea</h2>
         </div>
         <div v-else-if="isSettings()" class="popup-content">
            <div class="popup__settings-music">
               <h3>music</h3>
               <label for="player" :class="{ active: settings.music }">
                  <input type="checkbox" id="player" @click="toggleMusic()">
               </label>
            </div>
            <div class="popup__settings-level">
               <h3>difficulty:</h3>
               <div class="popup__settings-level-radio">
                  <label v-for="level in levelList" :key="level.name"
                     :class="{ active: level.name === settings.level.name }"
                     :for="level.name">
                     <input type="radio"
                        @click="changeLevel(level.name)"
                        name="level"
                        :id="level.name" />
                     {{ level.name }}
                  </label>
               </div>
            </div>
         </div>
         <div v-else-if="isRating()" class="popup-content">
            <h2>difficulty: {{ settings.level.name }}</h2>
            <ul v-if="ratingList[settings.level.name][0]"
               class="popup__rating-list">
               <li v-for="(ratingItem, index) in ratingList[settings.level.name]"
                  :key="ratingItem">
                  <span>{{ convertTime(ratingItem) }}</span>
                  <span>{{ index + 1 }}</span>
               </li>
            </ul>
            <h2 v-else>results not found</h2>
         </div>
         <div v-else-if="isVictory() || isDefeat()" class="popup-content">
            <img class="popup-stars"
               :src="require('@/assets/images/popups/stars-'
               + lastResault.starsCount + '.png')"
               alt="stars">
            <div v-if="popup.name === 'victory'" class="popup-score">
               <h3>current score</h3>
               <h2 class="popup-score-current">
                  {{ convertTime(lastResault.score) }}
               </h2>
               <h3>best score</h3>
               <h4 class="popup-score-best">
                  {{ convertTime(ratingList[settings.level.name][0]) }}
               </h4>
            </div>
         </div>

         <div v-if="isPause() || isVictory() || isDefeat()" class="popup-btns">
            <button class="retry-btn"
               @click="retry()">
               <img src="@/assets/images/popups/btns/retry.png" alt="retry button">
            </button>
            <button class="main-menu-btn"
               @click="hidePopup(); showMainMenu(); hidePlayField()">
               <img src="@/assets/images/popups/btns/main-menu.png" alt="menu button">
            </button>
         </div>
      </div>

      <button v-if="!isVictory() && !isDefeat()"
         class="popup-field-bg" :class="{ locked: popup.hideLock}"
         @click="hidePopup()">
      </button>
   </div>
</template>

<script>

export default {
   props: ['settings', 'levelList', 'ratingList', 'lastResault', 'stopTimer', 'startTimer', 'convertTime', 'timerStatus', 'startPlay', 'showMainMenu', 'hidePlayField', 'toggleMusic'],
   data() {
      return {
         popup: {
            name: null,
            hideLock: true,
            isActive: false,
         },
      };
   },
   methods: {
      getStarsCount() {
         const endTimeToLevel = this.timerStatus.countDown;
         const maxTimeToCompleteLevel = this.settings.level.maxTime;
         if (endTimeToLevel > maxTimeToCompleteLevel * 0.4) {
            return 3;
         } if (endTimeToLevel > maxTimeToCompleteLevel * 0.25) {
            return 2;
         } if (endTimeToLevel > maxTimeToCompleteLevel * 0.1) {
            return 1;
         }
         return 0;
      },
      showPopup(popupName) {
         let name = popupName;
         this.popup.isActive = true;

         if (name === 'pause') {
            this.stopTimer();
         } else if (name === 'result') {
            this.$parent.lastResault.starsCount = this.getStarsCount();

            const isVictory = this.timerStatus.countDown;
            if (isVictory) {
               const ratingOnCurrentLevel = this.ratingList[this.settings.level.name];
               const currentScore = this.settings.level.maxTime - this.timerStatus.countDown;

               const hasCurrentScoreOnRatingList = (ratingOnCurrentLevel
                  .includes(currentScore));
               if (!hasCurrentScoreOnRatingList) {
                  ratingOnCurrentLevel.push(currentScore);
                  const SortedRatingOnCurrentLevel = ratingOnCurrentLevel
                     .sort((a, b) => a - b)
                     .splice(0, 20);

                  this.$parent.ratingList[this.settings.level.name] = SortedRatingOnCurrentLevel;
                  localStorage.setItem('rating', JSON.stringify(this.ratingList));
               }
               this.$parent.lastResault.score = currentScore;
               name = 'victory';
            } else {
               name = 'defeat';
            }
         }

         const delayPopupLock = 500;
         this.popup.hideLock = setTimeout(() => {
            this.popup.hideLock = false;
         }, delayPopupLock);

         this.popup.name = name;
      },
      hidePopup() {
         this.popup.isActive = false;

         clearTimeout(this.popup.hideLock);

         if (this.popup.name === 'pause') {
            this.popup.hideLock = true;
            this.startTimer();
         }
      },
      retry() {
         this.hidePopup();
         this.stopTimer();
         this.startPlay();
      },
      setLevelSettings() {
         let cubesCount = this.settings.level.rowsCount ** 2;
         const isOdd = (cubesCount % 2 !== 0);
         if (isOdd) {
            cubesCount -= 1;
            this.$parent.settings.level.hasEmptyCell = true;
         } else {
            this.$parent.settings.level.hasEmptyCell = false;
         }
         const uniqueCubesCount = cubesCount / 2;
         this.$parent.settings.level.uniqueCubesCount = uniqueCubesCount;
      },
      changeLevel(selectedLevel) {
         const selectedLevelOnList = this.levelList
            .filter((level) => level.name === selectedLevel);
         [this.settings.level] = selectedLevelOnList;

         this.setLevelSettings();
         localStorage.setItem('settings', JSON.stringify(this.settings));
      },
      isPause() {
         return this.popup.name === 'pause';
      },
      isVictory() {
         return this.popup.name === 'victory';
      },
      isDefeat() {
         return this.popup.name === 'defeat';
      },
      isSettings() {
         return this.popup.name === 'settings';
      },
      isRating() {
         return this.popup.name === 'rating';
      },
   },
   mounted() {
      this.$emit('showPopup', this.showPopup);
   },
};
</script>

