<template>
   <div :v-show="$parent.isActive.playField"
      class="play-field" :class="{ active: $parent.isActive.playField }"
      :style="{ 'grid-template-columns': 'repeat(' + settings.level.rowsCount + ', 1fr)' }">
      <div class="play-field-cube"
         v-for="(cube, index) in cubesArr" :key="index">
         <button v-if="cube.name" @click="flipCube(index)"
            class="content" :class="{ locked: cube.locked, fliped: cube.fliped }">
            <img class="back-face"
               src="@/assets/images/play-field/cubes/back-face.png"
               alt="back-face" />
            <img v-if="cube.fliped"
               class="font-face"
               :src="require('@/assets/images/play-field/cubes/' + cube.name + '.png')"
               :alt="cube.name">
            <img v-else
               class="font-face"
               src=""
               alt="unknown">
         </button>
         <div v-else class="empty-cell"></div>
      </div>
   </div>
</template>

<script>
export default {
   props: ['settings', 'stopTimer', 'startTimer', 'showPopup'],
   data() {
      return {
         cubesArr: [{
            name: null,
            locked: null,
            fliped: null,
         }],
         flip: {
            prevCubeName: null,
            currentCubeName: null,
            stepsCount: 0,
            completedCount: 0,
            iPrev: 0,
         },
         uniqueCubesArr: [
            'arrow', 'wood', 'star', 'wave', 'skull', 'nut', 'branch', 'bomb', 'clock', 'arrow', 'wood', 'star', 'wave', 'skull', 'nut', 'branch', 'bomb', 'clock',
         ],
      };
   },
   methods: {
      randomizeArr(arr) {
         arr.sort(() => Math.random() - 0.5);
      },
      getCubes() {
         let cubesArr = [...this.uniqueCubesArr];
         this.randomizeArr(cubesArr);

         cubesArr.splice(this.settings.level.uniqueCubesCount);

         cubesArr = [...cubesArr, ...cubesArr];
         this.randomizeArr(cubesArr);

         cubesArr.forEach((cube, i) => {
            const cubeObj = {
               name: cube,
               locked: false,
               fliped: false,
            };
            cubesArr[i] = cubeObj;
         });

         if (this.settings.level.hasEmptyCell) {
            const cubesArrCenter = (cubesArr.length + 1) / 2;
            cubesArr.splice(cubesArrCenter, 0, { name: null, locked: true });
         }

         this.cubesArr = cubesArr;
      },
      flipCube(i) {
         const isLocked = this.cubesArr[i].locked;
         const isFliped = this.cubesArr[i].fliped;
         if (!isLocked && !isFliped) {
            this.cubesArr[i].locked = true;
            this.cubesArr[i].fliped = true;

            this.flip.stepsCount += 1;
            this.flip.prevCubeName = this.flip.currentCubeName;
            this.flip.currentCubeName = this.cubesArr[i].name;

            const isEven = (this.flip.stepsCount % 2 === 0);
            if (isEven) {
               const hasEqualCubes = (this.flip.prevCubeName === this.flip.currentCubeName);
               if (hasEqualCubes) {
                  this.cubesArr[this.flip.iPrev].locked = true;
                  this.flip.completedCount += 1;
                  const isCompleted = (
                     this.flip.completedCount === this.settings.level.uniqueCubesCount);
                  if (isCompleted) {
                     this.stopTimer();
                     this.showPopup('result');
                     this.flip.stepsCount = 0;
                  }
               } else {
                  const cubeObj = {
                     prevCube: this.cubesArr[this.flip.iPrev],
                     currentCube: this.cubesArr[i],
                  };
                  const delayBeforeUnlockedCube = 1000;
                  setTimeout(() => {
                     cubeObj.prevCube.locked = false;
                     cubeObj.currentCube.locked = false;
                  }, delayBeforeUnlockedCube);

                  const delayBeforeUnflipedCube = 2000;
                  setTimeout(() => {
                     cubeObj.prevCube.fliped = false;
                     cubeObj.currentCube.fliped = false;
                  }, delayBeforeUnflipedCube);
               }
            } else {
               this.flip.iPrev = i;
            }
         }
      },
      showPlayField() {
         const delayShowplayFieldAfterHideMainMenu = 1000;
         setTimeout(() => {
            this.$parent.isActive.topPanel = true;
            this.$parent.isActive.playField = true;
         }, delayShowplayFieldAfterHideMainMenu);
      },
      hidePlayField() {
         this.$parent.isActive.topPanel = false;
         this.$parent.isActive.playField = false;
         this.stopTimer();
      },
      startPlay() {
         this.showPlayField();

         this.flip.completedCount = 0;
         this.getCubes();

         const maxTimeToCompleteLevel = this.settings.level.maxTime;
         const animationTime = 1000;
         this.startTimer(maxTimeToCompleteLevel + animationTime);
      },
   },
   mounted() {
      this.$emit('startPlay', this.startPlay);
      this.$emit('hidePlayField', this.hidePlayField);
   },
};
</script>

<style lang="sass">
.play-field
   position: fixed
   display: grid
   gap: 25px
   top: 50%
   left: 50%
   transform: translate(-50%, -50%)
   opacity: 0
   visibility: hidden
   &.active
      opacity: 1
      visibility: visible

   &-cube
      position: relative
      top: 0
      left: 0
      max-width: 100px
      max-height: 100px
      aspect-ratio: 1
      perspective: 1000px
      .content
         width: 100%
         height: 100%
         transform-style: preserve-3d
         cursor: pointer
         &.locked
            transform: rotateY(180deg)
            cursor: auto
         img
            width: 100%
            height: 100%
         img:last-child
            position: absolute
            height: 100%
            width: 100%
            top: 0
            left: 0
            backface-visibility: hidden
            &:last-child
               transform: rotateY(180deg)

      &:hover
         transform: scale(110%)

</style>
