<template>
   <div class="top-panel" :class="{ active: $parent.isActive.topPanel }">
      <div class="top-panel-tools">
         <div class="top-panel-timer">
            <span>{{ convertTime(timerStatus.countDown) }}</span>
            <img src="@/assets/images/top-panel/timer.png" alt="timer">
         </div>
         <button class="pause-btn"
            @click="showPopup('pause')">
            <img src="@/assets/images/top-panel/pause.png" alt="pause button">
         </button>
      </div>
      <img class="top-panel-bg"
         src="@/assets/images/top-panel/top-panel.png"
         alt="top panel">
   </div>
</template>

<script>
export default {
   props: ['showPopup', 'convertTime'],
   data() {
      return {
         timerStatus: {
            countDown: null,
            setInterval: null,
            setTimeout: null,
            isActive: false,
         },
      };
   },
   methods: {
      stopTimer() {
         clearInterval(this.timerStatus.setInterval);
         clearTimeout(this.timerStatus.setTimeout);
         this.timerStatus.isActive = false;
      },
      startTimer(time = this.timerStatus.countDown) {
         const timerIsActive = this.timerStatus.isActive;
         if (!timerIsActive) {
            let countDown = time;
            const timerInterval = 1000;

            this.timerStatus.setInterval = setInterval(() => {
               countDown -= timerInterval;
               this.timerStatus.countDown = countDown;
            }, timerInterval);

            this.timerStatus.setTimeout = setTimeout(() => {
               this.timerStatus.countDown = 0;
               this.stopTimer();
            }, countDown);
            this.timerStatus.isActive = true;
         }
      },
   },
   mounted() {
      this.$emit('timer', {
         status: this.timerStatus,
         stop: this.stopTimer,
         start: this.startTimer,
      });
   },
};
</script>

